#include<bits/stdc++.h>
using namespace std;

int n;
double a[10001], sum;
int main() {
	cin >> n;
	for (int i = 1; i <= n; i++) cin >> a[i];
	sort(a + 1, a + 1 + n);
	for (int i = 2; i < n; i++) sum += (a[i] * 1.0);
	sum = sum * 1.0 / (n - 2);
	printf("%.2lf %.2lf", sum, max(fabs(a[2]-sum),fabs(a[n-1]-sum)));
	return 0;
}
